# Simple tone helper for letters\n\ndef rewrite_for_warmth(text, max_words=150, positive_keywords=None, banned_words=None):\n    # Deterministic, simple rules:\n    # - Replace \"Parkinson's disease\" with \"Parkinson's\".\n    # - Remove banned words if provided (case-insensitive exact word match).\n    # - If none of the positive_keywords are present (case-insensitive),\n    #   append the first positive keyword in lowercase at the end.\n    # - Trim to at most max_words words (whitespace-delimited).\n\n    positive_keywords = positive_keywords or []\n    banned_words = banned_words or []\n\n    t = text.replace("Parkinson's disease", "Parkinson's")\n\n    tokens = t.split()\n    lower_banned = set(w.lower() for w in banned_words)\n    filtered_tokens = [tok for tok in tokens if tok.lower() not in lower_banned]\n    t = " ".join(filtered_tokens)\n\n    lower_t = t.lower()\n    has_positive = any(k.lower() in lower_t for k in positive_keywords)\n    if not has_positive and positive_keywords:\n        t = t.rstrip() + " " + positive_keywords[0].lower()\n\n    words = t.split()\n    if len(words) > max_words:\n        t = " ".join(words[:max_words])\n\n    return t\n